package main

import (
	"strconv"
)

func solve(n int64) bool {
	s := strconv.Itoa(n)
	sum := 0
	product := 1
	for _, c := range s {
		digit := int(c - '0')
		sum += digit
		product *= digit
	}
	total := sum + product
	return n%total == 0
}
